+function serializeStackError(error: Error, superJson: SuperJSON): Record<string, any> {
+  const options = superJson.errorStackOptions!;
+  return serializeConfiguredError(error, options, superJson, 0, new Set<Error>());
+}
+
+function serializeConfiguredError(
+  error: Error,
+  options: NormalizedErrorStackOptions,
+  superJson: SuperJSON,
+  depth: number,
+  seen: Set<Error>
+): Record<string, any> {
+  const matches = matchesClass(error, options);
+  const output: Record<string, any> = {
+    name: error.name,
+    message: matches && options.sanitizeMessage
+      ? sanitizeMessage(error.message)
+      : error.message,
+  };
+
+  if (matches && options.mode === 'string' && superJson.allowedErrorProps.includes('stack') && typeof error.stack === 'string') {
+    output.stack = processStackString(error.stack, options);
+  }
+  if (matches && options.mode === 'frames' && superJson.allowedErrorProps.includes('stackFrames') && typeof error.stack === 'string') {
+    output.stackFrames = processStackFrames(error.stack, options);
+  }
+  if (error instanceof AggregateError) {
+    output.errors = error.errors;
+  }
+
+  const cause = (error as any).cause;
+  const canIncludeCause =
+    cause instanceof Error &&
+    !seen.has(cause) &&
+    (options.includeCauses === 'direct' && depth === 0 ||
+      options.includeCauses === 'deep' && depth < options.maxCauseDepth);
+  if (canIncludeCause) {
+    const nextSeen = new Set(seen);
+    nextSeen.add(error);
+    output.cause = serializeConfiguredError(cause, options, superJson, depth + 1, nextSeen);
+  }
+
+  const processor = superJson.errorClassRegistry.getProcessor(error.name);
+  return processor ? processor(output) : output;
+}
+
+function rehydrateStackError(value: Record<string, any>): Error {
+  const cause = value.cause && typeof value.cause === 'object'
+    ? rehydrateStackError(value.cause)
+    : undefined;
+  const error: Error = value.name === 'AggregateError' && typeof AggregateError !== 'undefined'
