import { NormalizedErrorStackOptions } from './error-options.js';

export function normalizeStackNewlines(stack: string): string {
  return stack.replace(/\r\n?/g, '\n');
}

function isInternalFrame(line: string, mode: NormalizedErrorStackOptions['stripInternalFrames']) {
  const node = line.includes('node:internal');
  const superjson = /src\/(?:transformer|plainer|index)\.ts/.test(line);
  return (
    (mode === 'node' && node) ||
    (mode === 'superjson' && superjson) ||
    (mode === 'node_and_superjson' && (node || superjson))
  );
}

function redactPath(line: string, options: NormalizedErrorStackOptions): string {
  if (options.redactPaths === 'strip_cwd') {
    const cwd = process.cwd().replace(/\\/g, '/');
    return line.replace(new RegExp(cwd.replace(/[.*+?^${}()|[\]\\]/g, '\\$&'), 'g'), '');
  }
  if (options.redactPaths === 'basename') {
    return line.replace(/(?:file:\/\/)?(?:[A-Za-z]:)?(?:\/|\\)[^\s()]+(?:\/|\\)([^\s()\\/]+)(?=[:)\s]|$)/g, '$1');
  }
  return line;
}

function processLines(stack: string, options: NormalizedErrorStackOptions): string[] {
  const normalized = options.normalizeNewlines ? normalizeStackNewlines(stack) : stack;
  let lines = normalized.split('\n').map((line, index) =>
    index > 0 && options.trimLeadingWhitespace ? line.replace(/^\s+/, '') : line
  );
  return lines;
}

export function processStackString(stack: string, options: NormalizedErrorStackOptions): string {
  let lines = processLines(stack, options).map(line => redactPath(line, options));
  if (options.maxStackLines !== undefined) lines = lines.slice(0, options.maxStackLines);
  return lines
    .filter((line, index) => index === 0 || !isInternalFrame(line, options.stripInternalFrames))
    .join('\n');
}

export function processStackFrames(stack: string, options: NormalizedErrorStackOptions): Array<{ raw: string }> {
  let lines = processLines(stack, options).filter(
    (line, index) => index === 0 || !isInternalFrame(line, options.stripInternalFrames)
  );
  lines = lines.map(line => redactPath(line, options));
  if (options.maxStackLines !== undefined) lines = lines.slice(0, options.maxStackLines);
  return lines.map(raw => ({ raw }));
}
export type ErrorStackMode = 'off' | 'string' | 'frames';
export type StripInternalFrames = 'none' | 'node' | 'superjson' | 'node_and_superjson';
export type RedactPaths = 'none' | 'basename' | 'strip_cwd';
export type IncludeCauses = 'none' | 'direct' | 'deep';

export interface ErrorStackOptions {
  mode?: ErrorStackMode;
  normalizeNewlines?: boolean;
  trimLeadingWhitespace?: boolean;
  maxStackLines?: number;
  stripInternalFrames?: StripInternalFrames;
  redactPaths?: RedactPaths;
  includeCauses?: IncludeCauses;
  maxCauseDepth?: number;
  sanitizeMessage?: boolean;
  classFilter?: string | string[];
}

export interface NormalizedErrorStackOptions {
  mode: ErrorStackMode;
  normalizeNewlines: boolean;
  trimLeadingWhitespace: boolean;
  maxStackLines?: number;
  stripInternalFrames: StripInternalFrames;
  redactPaths: RedactPaths;
  includeCauses: IncludeCauses;
  maxCauseDepth: number;
  sanitizeMessage: boolean;
  classFilter?: string[];
}

export function normalizeErrorStackOptions(
  input: unknown
): NormalizedErrorStackOptions | undefined {
  if (input === null || typeof input !== 'object' || Array.isArray(input)) {
    return undefined;
  }
  const options = input as ErrorStackOptions;
  const mode: ErrorStackMode =
    options.mode === 'string' || options.mode === 'frames' || options.mode === 'off'
      ? options.mode
      : 'off';
  const invalidMaxLines =
    options.maxStackLines !== undefined &&
    (!Number.isInteger(options.maxStackLines) || options.maxStackLines <= 0);
  const invalidCauseDepth =
    options.maxCauseDepth !== undefined && !Number.isInteger(options.maxCauseDepth);
  const classFilter = Array.isArray(options.classFilter)
    ? options.classFilter.filter((value): value is string => typeof value === 'string')
    : typeof options.classFilter === 'string'
    ? [options.classFilter]
    : undefined;

  return {
    mode: invalidMaxLines ? 'off' : mode,
    normalizeNewlines: options.normalizeNewlines === true,
    trimLeadingWhitespace: options.trimLeadingWhitespace !== false,
    maxStackLines: options.maxStackLines,
    stripInternalFrames:
      options.stripInternalFrames === 'node' ||
      options.stripInternalFrames === 'superjson' ||
      options.stripInternalFrames === 'node_and_superjson'
        ? options.stripInternalFrames
        : 'none',
    redactPaths:
      options.redactPaths === 'basename' || options.redactPaths === 'strip_cwd'
        ? options.redactPaths
        : 'none',
    includeCauses: invalidCauseDepth
      ? 'none'
      : options.includeCauses === 'direct' || options.includeCauses === 'deep'
      ? options.includeCauses
      : 'none',
    maxCauseDepth: options.maxCauseDepth === undefined ? 16 : options.maxCauseDepth,
    sanitizeMessage: options.sanitizeMessage === true,
    classFilter: classFilter?.length ? classFilter : undefined,
  };
}

